LEFT JOIN CIRD_OWNER.EXG_DIM ed ON ed.EXG_CD = t.exg_code
LEFT JOIN COMMON_OWNER.ACG_TP_DIM atd ON AP.ACG_TP_ID = atd.ACG_TP_ID
