LEFT JOIN TRANSACTIONS_OWNER.SRC_ENTR_CNL_TP_DIM sectd ON t.src_entr_cnl_tp_id = sectd.src_entr_cnl_tp_id
LEFT JOIN TRANSACTIONS_OWNER.TRD_SLCT_TP_DIM tstd ON t.trd_slct_tp_id = tstd.trd_slct_tp_id
LEFT JOIN COMMON_OWNER.SRC_STM_DIM ssd ON ssd.src_stm_id = t.src_stm_id
LEFT JOIN CCAL_REPL_OWNER.SRC_STM_DIM ssd2 ON t2.src_stm_id = stm.src_stm_id
LEFT JOIN COMMON_OWNER.DATE_DIM dd ON t.td = dd.cal_dt
LEFT JOIN CCAL_REPL_OWNER.TXN_RLTNP tr ON t.txn_id = tr.src_txn_id
LEFT JOIN CCAL_REPL_OWNER.APA a ON ap.exec_id = t.txn_id
LEFT JOIN CCAL_REPL_OWNER.CL_VAL cv ON cv.cl_val_id = t.txn_tp_id
LEFT JOIN CCAL_REPL_OWNER.CCAL_CIRD_PD_MAP ccpm ON ccpm.ccal_pd_id = ap.pd_id
