LEFT JOIN CCAL_REPL_OWNER.TXN t ON tr.trgt_txn_id = t2.txn_id
LEFT JOIN CCAL_REPL_OWNER.ACATS_BROKER ab ON b.broker_id = t.orig_src_stm_code
LEFT JOIN CCAL_REPL_OWNER.IMPCT_ACTION_LKU ial ON t.src_actn_code = impct_action_lku.action_code
