LEFT JOIN SSDS_DAL_OWNER.PERSON_AMS_DISCRETIONARY_STATUS_V padsv ON brk_own_resp_ams_disc.EMPLOYEE_ID = fa_number_v1.responsible_party_employee_id
LEFT JOIN SSDS_DAL_OWNER.ENTERPRISE_ENTITY_DIM_V eedv ON 1=0 /* TODO: no DRD AD ON clause; patch manually */
